import type { Product } from '../types';

// Produtos extras curados manualmente para cobrir categorias com poucos itens
// IDs prefixados com "ep-" para não colidir com os gerados pelo sync

function p(
  id: string,
  name: string,
  brand: string,
  category: Product['category'],
  description: string,
  image: string,
  tags: string[],
  colors: { name: string; image?: string }[] = [],
): Product {
  return {
    id: `ep-${id}`,
    name,
    brand,
    category,
    description,
    image,
    images: [image],
    averageRating: 0,
    reviewCount: 0,
    prices: [],
    tags,
    colors,
  };
}

